import React, { useState, useEffect } from 'react';
import { admin, cities } from '../utils/api';
import MapPicker from '../components/MapPicker';

const AdminDashboard = () => {
  const [places, setPlaces] = useState([]);
  const [cityList, setCityList] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingPlace, setEditingPlace] = useState(null);
  const [formData, setFormData] = useState({
    city_id: '',
    name: '',
    type: 'HOTEL',
    description: '',
    price: '',
    rating: '',
    latitude: '',
    longitude: ''
  });

  useEffect(() => {
    fetchPlaces();
    fetchCities();
  }, []);

  const fetchPlaces = async () => {
    try {
      const response = await admin.getPlaces();
      setPlaces(response.data);
    } catch (error) {
      console.error('Failed to fetch places:', error);
    }
  };

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Check required fields
    if (!formData.city_id || !formData.name || !formData.type || !formData.price || !formData.latitude || !formData.longitude) {
      alert('Please fill all required fields and select location on map');
      return;
    }

    try {
      const { rating, ...placeData } = formData; // Remove rating from submission
      if (editingPlace) {
        await admin.updatePlace(editingPlace.id, placeData);
      } else {
        await admin.addPlace(placeData);
      }

      fetchPlaces();
      resetForm();
    } catch (error) {
      console.error('Failed to save place:', error);
      alert('Failed to save place: ' + error.message);
    }
  };

  const handleEdit = (place) => {
    setEditingPlace(place);
    setFormData({
      city_id: place.city_id,
      name: place.name,
      type: place.type,
      description: place.description,
      price: place.price,
      latitude: place.latitude,
      longitude: place.longitude
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this place?')) {
      try {
        await admin.deletePlace(id);
        fetchPlaces();
      } catch (error) {
        console.error('Failed to delete place:', error);
      }
    }
  };

  const handleLocationSelect = (lat, lng) => {
    setFormData({
      ...formData,
      latitude: lat,
      longitude: lng
    });
  };

  const resetForm = () => {
    setFormData({
      city_id: '',
      name: '',
      type: 'HOTEL',
      description: '',
      price: '',
      latitude: '',
      longitude: ''
    });
    setEditingPlace(null);
    setShowForm(false);
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'HOTEL': return '#3b82f6';
      case 'RESTAURANT': return '#ef4444';
      case 'ATTRACTION': return '#10b981';
      default: return '#6b7280';
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.title}>Admin Dashboard</h2>
        <button 
          onClick={() => setShowForm(!showForm)} 
          style={styles.addButton}
        >
          {showForm ? 'Cancel' : 'Add New Place'}
        </button>
      </div>

      {showForm && (
        <div style={styles.formContainer}>
          <h3>{editingPlace ? 'Edit Place' : 'Add New Place'}</h3>
          <form onSubmit={handleSubmit} style={styles.form}>
            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>City:</label>
                <select
                  value={formData.city_id}
                  onChange={(e) => setFormData({...formData, city_id: e.target.value})}
                  style={styles.input}
                  required
                >
                  <option value="">Select City</option>
                  {cityList.map(city => (
                    <option key={city.id} value={city.id}>{city.name}</option>
                  ))}
                </select>
              </div>

              <div style={styles.formField}>
                <label style={styles.label}>Type:</label>
                <select
                  value={formData.type}
                  onChange={(e) => setFormData({...formData, type: e.target.value})}
                  style={styles.input}
                  required
                >
                  <option value="HOTEL">Hotel</option>
                  <option value="RESTAURANT">Restaurant</option>
                  <option value="ATTRACTION">Attraction</option>
                </select>
              </div>
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Name:</label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                style={styles.input}
                required
              />
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Description:</label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
                style={styles.textarea}
                rows="3"
              />
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Select Location on Map:</label>
              <MapPicker 
                onLocationSelect={handleLocationSelect}
                initialLat={parseFloat(formData.latitude) || 27.7172}
                initialLng={parseFloat(formData.longitude) || 85.3240}
                selectedCityId={formData.city_id}
              />
            </div>

            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>Price (NPR):</label>
                <input
                  type="number"
                  step="0.01"
                  value={formData.price}
                  onChange={(e) => setFormData({...formData, price: e.target.value})}
                  style={styles.input}
                  required
                />
              </div>
            </div>

            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>Latitude (Auto-filled):</label>
                <input
                  type="number"
                  step="any"
                  value={formData.latitude}
                  onChange={(e) => setFormData({...formData, latitude: e.target.value})}
                  style={{...styles.input, backgroundColor: '#f3f4f6'}}
                  readOnly
                />
              </div>

              <div style={styles.formField}>
                <label style={styles.label}>Longitude (Auto-filled):</label>
                <input
                  type="number"
                  step="any"
                  value={formData.longitude}
                  onChange={(e) => setFormData({...formData, longitude: e.target.value})}
                  style={{...styles.input, backgroundColor: '#f3f4f6'}}
                  readOnly
                />
              </div>
            </div>

            <div style={styles.formActions}>
              <button type="submit" style={styles.saveButton}>
                {editingPlace ? 'Update Place' : 'Add Place'}
              </button>
              <button type="button" onClick={resetForm} style={styles.cancelButton}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      <div style={styles.placesContainer}>
        <h3>All Places ({places.length})</h3>
        <div style={styles.placesGrid}>
          {places.map(place => (
            <div key={place.id} style={styles.placeCard}>
              <div style={styles.placeHeader}>
                <h4 style={styles.placeName}>{place.name}</h4>
                <span style={{...styles.typeTag, backgroundColor: getTypeColor(place.type)}}>
                  {place.type}
                </span>
              </div>

              <p style={styles.cityName}>{place.city_name}</p>
              <p style={styles.description}>{place.description}</p>

              <div style={styles.placeDetails}>
                <span style={styles.price}>NPR {place.price}</span>
                <span style={styles.rating}>★ {place.rating}</span>
              </div>

              <div style={styles.coordinates}>
                {place.latitude}, {place.longitude}
              </div>

              <div style={styles.actions}>
                <button 
                  onClick={() => handleEdit(place)} 
                  style={styles.editButton}
                >
                  Edit
                </button>
                <button 
                  onClick={() => handleDelete(place.id)} 
                  style={styles.deleteButton}
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

